@staticmethod
    def get_entry(
        calc_docs: list[Calculation], job_id: str | None = None
    ) -> ComputedEntry:
        """Get a computed entry from a list of FHI-aims calculation documents.

        Parameters
        ----------
        calc_docs: List[.Calculation]
            A list of FHI-aims calculation documents.
        job_id: Optional[str]
            The job identifier.

        Returns
        -------
        ComputedEntry
            A computed entry.
